// Hard-coded data — no API call or state yet
const PRODUCTS = [
  { category: 'Sporting Goods', name: 'Football', price: '$49.99', stocked: true },
  { category: 'Sporting Goods', name: 'Baseball', price: '$9.99',  stocked: true },
  { category: 'Electronics',   name: 'iPod Touch', price: '$99.99', stocked: true },
  { category: 'Electronics',   name: 'iPhone 5',   price: '$399.99', stocked: false },
];

function ProductRow({ product }) {
  const name = product.stocked
    ? product.name
    : <span style={{ color: 'red' }}>{product.name}</span>;
  return (
    <tr>
      <td>{name}</td>
      <td>{product.price}</td>
    </tr>
  );
}

function ProductCategoryRow({ category }) {
  return (
    <tr>
      <th colSpan="2">{category}</th>
    </tr>
  );
}

function ProductTable({ products }) {
  const rows = [];
  let lastCategory = null;

  products.forEach(product => {
    if (product.category !== lastCategory) {
      rows.push(<ProductCategoryRow key={product.category} category={product.category} />);
      lastCategory = product.category;
    }
    rows.push(<ProductRow key={product.name} product={product} />);
  });

  return (
    <table>
      <thead><tr><th>Name</th><th>Price</th></tr></thead>
      <tbody>{rows}</tbody>
    </table>
  );
}

function SearchBar() {
  return (
    <form>
      <input type="text" placeholder="Search..." />
      <label><input type="checkbox" /> Only show products in stock</label>
    </form>
  );
}

function FilterableProductTable({ products }) {
  return (
    <div>
      <SearchBar />
      <ProductTable products={products} />
    </div>
  );
}

export default function App() {
  return <FilterableProductTable products={PRODUCTS} />;
}

{
  "categories": [
    {
      "name": "Sporting Goods",
      "products": [
        { "id": 1, "name": "Football", "price": 49.99, "stocked": true }
      ]
    }
  ]
}

function Tag({ label }) {
  return <span className="tag">{label}</span>;
}

function TagCloud({ tags }) {
  return <div>{tags.map(t => <Tag key={t} label={t} />)}</div>;
}

function PostCard({ title, date, excerpt }) {
  return (
    <article>
      <h2>{title}</h2>
      <time>{date}</time>
      <p>{excerpt}</p>
    </article>
  );
}

function PostList({ posts }) {
  return (
    <section>
      {posts.map(p => <PostCard key={p.id} {...p} />)}
    </section>
  );
}

function Sidebar({ tags }) {
  return (
    <aside>
      <TagCloud tags={tags} />
      <NewsletterSignup />
    </aside>
  );
}

function TwoColumnLayout({ left, right }) {
  return (
    <div className="two-col">
      <div>{left}</div>
      <div>{right}</div>
    </div>
  );
}

function BlogHomePage({ posts, tags }) {
  return (
    <>
      <Hero />
      <TwoColumnLayout
        left={<PostList posts={posts} />}
        right={<Sidebar tags={tags} />}
      />
    </>
  );
}

// Before writing the component body, declare what it needs:
// ProductRow: { product: { name, price, stocked } }
// ProductCategoryRow: { category: string }
// ProductTable: { products: Array<{ category, name, price, stocked }> }
// SearchBar: {}  (no data yet — search text will be state later)
// FilterableProductTable: { products: Array<...> }

// This exercise reveals the data flow before you write a single line of JSX.

// Static version
function FilterableProductTable({ products }) {
  return (
    <div>
      <SearchBar />
      <ProductTable products={products} />
    </div>
  );
}

// After adding state (steps 3-5):
function FilterableProductTable({ products }) {
  const [filterText, setFilterText] = React.useState('');
  const [inStockOnly, setInStockOnly] = React.useState(false);

  const filtered = products.filter(p =>
    p.name.toLowerCase().includes(filterText.toLowerCase()) &&
    (!inStockOnly || p.stocked)
  );

  return (
    <div>
      <SearchBar
        filterText={filterText}
        inStockOnly={inStockOnly}
        onFilterChange={setFilterText}
        onStockChange={setInStockOnly}
      />
      <ProductTable products={filtered} />
    </div>
  );
}

// Instead of:
function SearchBar() {
  return (
    <form>
      <input type="text" placeholder="Search..." />
      <label><input type="checkbox" /> Only show in stock</label>
    </form>
  );
}

// With a design system (e.g. shadcn/ui):
import { Input } from '@/components/ui/input';
import { Checkbox } from '@/components/ui/checkbox';
import { Label } from '@/components/ui/label';

function SearchBar() {
  return (
    <form className="space-y-2">
      <Input type="search" placeholder="Search products..." />
      <div className="flex items-center gap-2">
        <Checkbox id="stock" />
        <Label htmlFor="stock">Only show in stock</Label>
      </div>
    </form>
  );
}
